    const slopeCounts = new Map();

    // Iterate over all pairs of points
    for (let i = 0; i < n; i++) {
        const [x1, y1] = points[i];
        for (let j = i + 1; j < n; j++) {
            const [x2, y2] = points[j];
            let slope;
            if (x1 === x2) {
                slope = Infinity; // Vertical line
            } else {
                slope = (y2 - y1) / (x2 - x1);
