            if (slopeCounts.has(slope)) {
                slopeCounts.set(slope, slopeCounts.get(slope) + 1);
            } else {
                slopeCounts.set(slope, 1);
            }
        }
    }

    let count = 0;

    // For each slope, calculate the number of pairs of points with that slope
    for (const [slope, cnt] of slopeCounts.entries()) {
        // Number of ways to choose 2 points with this slope
        const ways = cnt * (cnt - 1) / 2;
        // Add to the total count of trapezoids
        count += ways;
    }

    return count;
}
